H = zeros(nMax,1);

% P(Lq = 0) → system has <= s customers
H(1) = sum(P(1:s+1));

% P(Lq = k), k >= 1
for k = 1:nMax-1
    idx = k + s + 1;

    if idx <= length(P)
        H(k+1) = P(idx);
    else
        H(k+1) = 0;
    end
end

